// Access both merged inputs
// Input 0 (from Bark API Call): contains audio_base64, sample_rate, format
// Input 1 (from Store Input): contains channel, text, voice_preset, output_format
const allInputs = $input.all();
const barkResponse = allInputs[0]?.json || {};
const stored = allInputs[1]?.json || {};

const audio_base64 = barkResponse.audio_base64 || '';
const sample_rate = barkResponse.sample_rate || 0;
const format = barkResponse.format || 'wav';

return [{
  json: {
    success: !!audio_base64,
    format: format,
    sample_rate: sample_rate,
    audio_size_bytes: audio_base64.length,
    timestamp: new Date().toISOString(),
    channel: stored.channel || '#general',
    text: stored.text || '',
    voice_preset: stored.voice_preset || 'v2/en_speaker_6',
    output_format: stored.output_format || 'wav'
  }
}];
